(function(){function e(){const n=document.querySelectorAll(".mobile-bottom-nav .nav-item");if(!n.length)return;const a=window.location.pathname.split("/").pop()||"index.html";n.forEach(t=>{const o=t.getAttribute("data-page")+".html";t.classList.remove("active"),(a===o||a===""&&o==="index.html")&&t.classList.add("active")})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",e):e()})();
